#!/usr/bin/env node
/*
 * CPL Dashboard builder
 * -----------------------------------------------------------------------------
 * Pulls the Bounce Pickleball League API, transforms the raw endpoint JSON into
 * the shape the dashboard expects, and writes a self-contained standings HTML.
 *
 * Requirements: Node 18+ (uses the built-in global fetch). No npm install needed.
 *
 * Usage:   node build.js
 * Output:  ./standings_dashboard.html   (single self-contained file)
 *
 * Config below can be overridden with env vars:
 *   CPL_BASE      API base URL
 *   CPL_DIVISION  division id
 *   CPL_OUT       output html path
 *   CPL_TEMPLATE  template html path
 */

const fs = require("fs");
const path = require("path");

const BASE = process.env.CPL_BASE
  || "https://cplsecureapiproxy.azurewebsites.net/api/CPLSecureApiProxy/local/v0/api";
const DIVISION = process.env.CPL_DIVISION || "3e9b6a58-8823-46d9-8f00-81d53e63f0eb";
const OUT = process.env.CPL_OUT || path.join(__dirname, "standings_dashboard.html");
const TEMPLATE = process.env.CPL_TEMPLATE || path.join(__dirname, "template.html");

// Embedded copy of template.html so this script is fully self-contained
// (a single .js file is all you need). If a template.html file is present next
// to the script, or CPL_TEMPLATE points to one, that file is used instead.
const TEMPLATE_B64 = "";

// ----- helpers ---------------------------------------------------------------
const round1 = n => Math.round(n * 10) / 10;
// Normalize names so the same person matches across endpoints (collapse spaces,
// Title Case). Mirrors the league's inconsistent casing ("steven garfinkel").
const norm = s => (s || "").replace(/\s+/g, " ").trim().toLowerCase()
  .replace(/\b\w/g, c => c.toUpperCase());

// .NET ReferenceHandler wraps arrays as {$id, $values:[...]}. Find the first
// $values array under a key (used for the players endpoint shape).
function firstValues(obj) {
  if (!obj || typeof obj !== "object") return null;
  if (Array.isArray(obj.$values)) return obj.$values;
  for (const k of Object.keys(obj)) {
    const r = firstValues(obj[k]);
    if (r) return r;
  }
  return null;
}

async function getJSON(url) {
  const r = await fetch(url, { headers: { Accept: "application/json" } });
  if (!r.ok) throw new Error(`HTTP ${r.status} fetching ${url}`);
  return r.json();
}

// ----- main ------------------------------------------------------------------
async function main() {
  console.log("Fetching season matchups …");
  const feed = await getJSON(`${BASE}/divisions/${DIVISION}/matchups`);
  const matchups = (feed.$values || firstValues(feed) || []);
  const completed = matchups.filter(m => m.endResult); // endResult null = unplayed
  console.log(`  ${matchups.length} scheduled, ${completed.length} completed.`);
  if (!completed.length) throw new Error("No completed matches yet — nothing to build.");

  const TEAMNAME = {};                 // teamId -> team name
  const players = new Map();           // playerId -> aggregate record
  const teams = new Map();             // teamName -> standings record
  const weeksSeen = new Set();

  const ensureTeam = name => {
    if (!teams.has(name)) teams.set(name, { name, w: 0, l: 0, pf: 0, pa: 0, gw: 0, gl: 0 });
    return teams.get(name);
  };

  for (const mu of completed) {
    process.stdout.write(`Fetching match wk${mu.weekNumber} ${mu.homeName} vs ${mu.awayName} … `);
    const d = await getJSON(`${BASE}/divisions/${DIVISION}/matchups/${mu.matchupId}`);
    const M = d.matchup;
    const homeId = M.homeTeamId, awayId = M.awayTeamId;
    TEAMNAME[homeId] = M.homeName; TEAMNAME[awayId] = M.awayName;
    weeksSeen.add(M.weekNumber);

    const ps = (d.matchupPlayerStats && d.matchupPlayerStats.$values) || [];
    const games = (d.lineups && d.lineups.lineups && d.lineups.lineups.$values) || [];

    // team game wins from the actual game scores
    let hgw = 0, agw = 0;
    for (const g of games) (g.homeScore > g.awayScore ? hgw++ : agw++);

    const home = { id: homeId, name: M.homeName, points: M.homePoints, gw: hgw };
    const away = { id: awayId, name: M.awayName, points: M.awayPoints, gw: agw };
    const homeWon = M.homePoints > M.awayPoints;

    // team standings
    ensureTeam(home.name); ensureTeam(away.name);
    teams.get(home.name).pf += home.points; teams.get(home.name).pa += away.points;
    teams.get(away.name).pf += away.points; teams.get(away.name).pa += home.points;
    teams.get(home.name).gw += hgw; teams.get(home.name).gl += agw;
    teams.get(away.name).gw += agw; teams.get(away.name).gl += hgw;
    (homeWon ? teams.get(home.name) : teams.get(away.name)).w++;
    (homeWon ? teams.get(away.name) : teams.get(home.name)).l++;

    // id -> normalized name for this match (for game-log partner/opponents)
    const id2name = {};
    for (const p of ps) id2name[p.playerId] = norm(`${p.firstName} ${p.lastName}`);

    // per-player per-match aggregates + match log
    for (const p of ps) {
      if (!p.gamesPlayed) continue;
      const pid = p.playerId;
      if (!players.has(pid)) {
        players.set(pid, {
          name: norm(`${p.firstName} ${p.lastName}`), gender: p.gender,
          team: TEAMNAME[p.teamId], matches: 0,
          gamesPlayed: 0, wins: 0, losses: 0, pointsWon: 0, totalPointsAgainst: 0,
          mixedWins: 0, mixedLosses: 0, genderWins: 0, genderLosses: 0,
          clutchWins: 0, clutchLosses: 0, log: [], games: [],
        });
      }
      const P = players.get(pid);
      P.matches++;
      P.gamesPlayed += p.gamesPlayed; P.wins += p.wins; P.losses += p.losses;
      P.pointsWon += p.pointsWon; P.totalPointsAgainst += p.totalPointsAgainst;
      P.mixedWins += p.mixedWins; P.mixedLosses += p.mixedLosses;
      P.genderWins += p.genderWins; P.genderLosses += p.genderLosses;
      P.clutchWins += p.clutchWins; P.clutchLosses += p.clutchLosses;

      const mine = (p.teamId === homeId) ? home : away;
      const opp = (p.teamId === homeId) ? away : home;
      const teamWon = (mine === home) ? homeWon : !homeWon;
      P.log.push({
        week: M.weekNumber, opp: opp.name, homeAway: (mine === home) ? "H" : "A",
        w: p.wins, l: p.losses, gp: p.gamesPlayed, pf: p.pointsWon, pa: p.totalPointsAgainst,
        mx: [p.mixedWins, p.mixedLosses], gn: [p.genderWins, p.genderLosses],
        cl: [p.clutchWins, p.clutchLosses],
        teamRes: teamWon ? "W" : "L", teamGW: mine.gw, teamGL: opp.gw,
      });
    }

    // game-by-game log (4 perspectives per game)
    for (const g of games) {
      const persp = [
        [g.homePlayerId1, g.homePlayerId2, away.name, g.awayPlayerId1, g.awayPlayerId2, g.homeScore, g.awayScore],
        [g.homePlayerId2, g.homePlayerId1, away.name, g.awayPlayerId1, g.awayPlayerId2, g.homeScore, g.awayScore],
        [g.awayPlayerId1, g.awayPlayerId2, home.name, g.homePlayerId1, g.homePlayerId2, g.awayScore, g.homeScore],
        [g.awayPlayerId2, g.awayPlayerId1, home.name, g.homePlayerId1, g.homePlayerId2, g.awayScore, g.homeScore],
      ];
      for (const [me, partner, oppTeam, o1, o2, my, their] of persp) {
        const P = players.get(me);
        if (!P) continue; // safety (sub with 0 stat rows shouldn't happen)
        P.games.push({
          wk: M.weekNumber, opp: oppTeam, t: g.matchType,
          with: id2name[partner] || "", vs: [id2name[o1] || "", id2name[o2] || ""],
          f: my, a: their, w: my > their ? 1 : 0,
        });
      }
    }
  }

  // league rank + dupr id from the players endpoint
  console.log("Fetching division players (rankings) …");
  let rankByName = {};
  try {
    const pj = await getJSON(`${BASE}/divisions/${DIVISION}/players`);
    const list = firstValues(pj) || [];
    for (const p of list) {
      const key = norm(`${p.firstName} ${p.lastName}`);
      if (p.ranking != null) rankByName[key] = p.ranking;
    }
    console.log(`  ${Object.keys(rankByName).length} ranked players.`);
  } catch (e) {
    console.warn("  WARN: players endpoint failed, league rank column will be blank:", e.message);
  }

  // finalize players
  const playerArr = [];
  for (const P of players.values()) {
    P.winPct = P.gamesPlayed ? round1(100 * P.wins / P.gamesPlayed) : 0;
    P.diff = P.pointsWon - P.totalPointsAgainst;
    P.ppg = P.gamesPlayed ? round1(P.pointsWon / P.gamesPlayed) : 0;
    P.leagueRank = rankByName[norm(P.name)] ?? null;
    P.log.sort((a, b) => a.week - b.week);   // stable: keeps intra-match order
    P.games.sort((a, b) => a.wk - b.wk);
    playerArr.push(P);
  }
  playerArr.sort((a, b) => (b.winPct - a.winPct) || (b.diff - a.diff));

  // finalize teams
  const teamArr = [...teams.values()];
  for (const t of teamArr) t.diff = t.pf - t.pa;
  teamArr.sort((a, b) => (b.w - a.w) || (b.diff - a.diff));

  const weeks = [...weeksSeen].sort((a, b) => a - b);
  const weekLabel = weeks.length ? (weeks[0] === weeks[weeks.length - 1]
    ? `${weeks[0]}` : `${weeks[0]}-${weeks[weeks.length - 1]}`) : "";

  const DATA = {
    players: playerArr, teams: teamArr,
    meta: {
      matchesPlayed: completed.length, weeks: weekLabel,
      asOf: new Date().toISOString().slice(0, 10), totalPlayers: playerArr.length,
    },
  };

  // sanity checks (fail loudly rather than ship bad data)
  for (const t of teamArr) {
    const tot = t.gw + t.gl;
    if (tot % 32 !== 0) console.warn(`WARN: ${t.name} games ${t.gw}-${t.gl} not a multiple of 32`);
  }
  for (const P of playerArr) {
    const gWins = P.games.filter(g => g.w).length;
    if (P.games.length !== P.gamesPlayed || gWins !== P.wins) {
      console.warn(`WARN: ${P.name} game-log mismatch (games ${P.games.length}/${P.gamesPlayed}, wins ${gWins}/${P.wins})`);
    }
  }

  let template;
  if (process.env.CPL_TEMPLATE && fs.existsSync(process.env.CPL_TEMPLATE)) {
    template = fs.readFileSync(process.env.CPL_TEMPLATE, "utf8");
  } else if (fs.existsSync(TEMPLATE)) {
    template = fs.readFileSync(TEMPLATE, "utf8");
  } else {
    template = Buffer.from(TEMPLATE_B64, "base64").toString("utf8");
  }
  if (!template.includes("const DATA = __DATA__;"))
    throw new Error("template.html is missing the `const DATA = __DATA__;` placeholder");
  const html = template.replace("const DATA = __DATA__;", "const DATA = " + JSON.stringify(DATA) + ";");
  fs.writeFileSync(OUT, html);
  console.log(`\n✓ Wrote ${OUT}`);
  console.log(`  ${DATA.meta.matchesPlayed} matches · ${DATA.meta.totalPlayers} players · weeks ${DATA.meta.weeks} · as of ${DATA.meta.asOf}`);
  console.log("  Standings:");
  teamArr.forEach((t, i) => console.log(`   #${i + 1} ${t.name}  ${t.w}-${t.l}  games ${t.gw}-${t.gl}  (${t.diff >= 0 ? "+" : ""}${t.diff})`));
}

main().catch(e => { console.error("\nBuild failed:", e.message); process.exit(1); });
